import{_ as t,o as a,c as i,ak as s}from"./chunks/framework.BbJJwCwT.js";const u=JSON.parse('{"title":"DARTS Search Pipeline","description":"Conceptual DARTS workflow mapped onto actual ForeBlocks modules.","frontmatter":{"title":"DARTS Search Pipeline","description":"Conceptual DARTS workflow mapped onto actual ForeBlocks modules.","editLink":true,"foreBlocksVersion":"0.1.34"},"headers":[],"relativePath":"architecture/darts-pipeline.md","filePath":"architecture/darts-pipeline.md"}'),r={name:"architecture/darts-pipeline.md"};function d(n,e,l,o,c,p){return a(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="darts-search-pipeline" tabindex="-1">DARTS Search Pipeline <a class="header-anchor" href="#darts-search-pipeline" aria-label="Permalink to “DARTS Search Pipeline”">​</a></h1><p>This page maps the conceptual DARTS workflow onto the actual ForeBlocks modules.</p><h2 id="why-this-pipeline-exists" tabindex="-1">Why this pipeline exists <a class="header-anchor" href="#why-this-pipeline-exists" aria-label="Permalink to “Why this pipeline exists”">​</a></h2><p>ForeBlocks does not treat DARTS as a single opaque training call. The search stack is deliberately staged so you can:</p><ul><li>prune bad candidates early with cheap signals</li><li>spend short differentiable-search budgets only on promoted candidates</li><li>derive a discrete architecture explicitly</li><li>retrain the final model from scratch when desired</li></ul><p>That structure makes it easier to debug, benchmark, and reason about the search than a monolithic NAS loop.</p><h2 id="phase-to-module-map" tabindex="-1">Phase-to-module map <a class="header-anchor" href="#phase-to-module-map" aria-label="Permalink to “Phase-to-module map”">​</a></h2><table tabindex="0"><thead><tr><th>Phase</th><th>Main code location</th><th>Role</th></tr></thead><tbody><tr><td>search-space definition</td><td><code>darts/config.py</code></td><td>defines architecture modes, op pools, and search budgets</td></tr><tr><td>candidate generation</td><td><code>darts/search/orchestrator.py</code></td><td>samples candidate configs and coordinates evaluation</td></tr><tr><td>zero-cost ranking</td><td><code>darts/search/zero_cost.py</code></td><td>computes cheap pre-training metrics</td></tr><tr><td>bilevel search training</td><td><code>darts/training/darts_loop.py</code></td><td>runs the mixed-architecture DARTS phase</td></tr><tr><td>multi-fidelity orchestration</td><td><code>darts/search/multi_fidelity.py</code></td><td>promotes top candidates and manages staged budgets</td></tr><tr><td>final fixed-model retraining</td><td><code>darts/training/final_trainer.py</code></td><td>retrains the derived architecture</td></tr><tr><td>result analysis</td><td><code>darts/evaluation/analyzer.py</code></td><td>builds search-result summaries and plots</td></tr><tr><td>public entry surface</td><td><code>darts/trainer.py</code></td><td>exposes the staged workflow as <code>DARTSTrainer</code> methods</td></tr></tbody></table><h2 id="public-control-flow" tabindex="-1">Public control flow <a class="header-anchor" href="#public-control-flow" aria-label="Permalink to “Public control flow”">​</a></h2><p>The high-level path is:</p><ol><li>instantiate <code>DARTSTrainer</code></li><li>call <code>multi_fidelity_search(...)</code></li><li>inspect the returned candidates and final metrics</li><li>save the best final model</li></ol><p>Internally, the call chain is roughly:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>DARTSTrainer.multi_fidelity_search(...)</span></span>
<span class="line"><span>  -&gt; search/multi_fidelity.py</span></span>
<span class="line"><span>      -&gt; search/orchestrator.py</span></span>
<span class="line"><span>      -&gt; search/zero_cost.py</span></span>
<span class="line"><span>      -&gt; training/darts_loop.py</span></span>
<span class="line"><span>      -&gt; trainer.derive_final_architecture(...)</span></span>
<span class="line"><span>      -&gt; training/final_trainer.py</span></span></code></pre></div>`,13)])])}const m=t(r,[["render",d]]);export{u as __pageData,m as default};
